            // With store:false (mutant), the highly compressible content would be compressed to ~100 bytes
            // So the threshold of 5000 bytes distinguishes the two behaviors
            expect(zipSize).toBeGreaterThan(5000);
        } finally {
            fs.rmSync(tmpDir, { recursive: true, force: true });
        }
